#include <bits/stdc++.h>
using namespace std;
int main(){
    int n;
    cin >> n;
    vector<int> nums(n);
    for(int i = 0; i < n; i++) cin >> nums[i];
    unordered_map<int, int> count;
    int repeating = -1;
    for(int num : nums){
        if(count.find(num) != count.end())
            repeating = num;
        count[num]++;
    }
    for(int i = 1; i <= n; i++){
        if(count.find(i) == count.end()){
            cout << repeating << ' ' << i;
            return 0;
        }
    }
    cout << "None";
}
